{"type":"TOOL_CALL_RESULT","timestamp":1773296477,"rawEvent":{"message_id":"019ce0b46c877b2e8b0225046def72ab","conversation_id":"019ce0b2bc5575239725bf81fcda9410","tool_call_id":"tooluse_dVM7U3fXHiqE7LjyoqkY3R","result":{"content":" // 1. 每次点击，先强制把所有文章隐去并下沉，制造“刷新”感
 pubItems.forEach(item => {
 item.style.opacity = '0';
 item.style.transform = 'translateY(10px)';
 });

 // 2. 稍微等待 150ms（让隐去动画执行一半），然后再执行重新排列
 setTimeout(() => {
 let delay = 0; // 用于控制瀑布流的延迟时间

 pubItems.forEach(item => {
 const itemTags = item.getAttribute('data-tags');

 // 如果符合过滤条件
 if (filterValue === 'all' || (itemTags && itemTags.includes(filterValue))) {
 item.classList.remove('hidden'); // 取消隐藏

 // 3. 瀑布流渐入：每篇文章比上一篇晚 50ms 浮现
 setTimeout(() => {
 item.style.opacity = '1';
 item.style.transform = 'translateY(0)';
 }, delay);
 delay += 50; 

 } else {
 // 不符合条件，直接彻底隐藏
 item.classList.add('hidden');
 }
 });
 }, 150);
 }
 });
 </script>

 <script>
 // --------------------------------------------------------
 // 1. 通用格式化函数 (例如: 1234 -> 1.2k)
 // --------------------------------------------------------
 function formatNumber(count) {
 if (count >= 1000) {
 return (count / 1000).toFixed(1) + 'k';
 }
 return count.toString();
 }

 // --------------------------------------------------------
 // 2. GitHub Stars 抓取逻辑
 // --------------------------------------------------------
 async function fetchGitHubStars(repo) {
 try {
 const response = await fetch(`https://api.github.com/repos/${repo}`, {
 headers: { 'Accept': 'application/vnd.github.v3+json' }
 });
 if (response.ok) {
 const data = await response.json();
 return data.stargazers_count;
 }
 if (response.status === 403) console.warn(`GitHub Rate limit exceeded for ${repo}`);
 } catch (error) {
 console.error(`Error fetching stars for ${repo}:`, error);
 }
 return null;
 }

 async function updateAllStars() {
 const starElements = document.querySelectorAll('.github-stars[data-github-repo]');
 if (starElements.length === 0) return;

 const repos = new Set();
 starElements.forEach(el => repos.add(el.getAttribute('data-github-repo')));

 const results = [];
 for (const repo of repos) {
 const stars = await fetchGitHubStars(repo);
 results.push({ repo, stars });
 await new Promise(resolve => setTimeout(resolve, 200)); // 防止 GitHub API 限流
 }

 starElements.forEach(el => {
 const repo = el.getAttribute('data-github-repo');
 const result = results.find(r => r.repo === repo);
 if (result && result.stars !== null) {
 el.textContent = `⭐ ${formatNumber(result.stars)}`;
 el.style.display = 'inline';
 }
 });
 }

 // --------------------------------------------------------
 // 3. Semantic Scholar 引用量抓取逻辑
 // --------------------------------------------------------
 async function fetchCitations(identifier, isArxiv = false) {
 try {
 // S2 API 支持直接通过 arXiv ID 查询: /paper/ARXIV:1234.56789
 const apiEndpoint = isArxiv 
 ? `https://api.semanticscholar.org/graph/v1/paper/ARXIV:${identifier}?fields=citationCount`
 : `https://api.semanticscholar.org/graph/v1/paper/${identifier}?fields=citationCount`;

 const response = await fetch(apiEndpoint);
 if (response.ok) {
 const data = await response.json();
 return data.citationCount;
 }
 } catch (error) {
 console.error(`Error fetching citations for ${identifier}:`, error);
 }
 return null;
 }

 async function updateAllCitations() {
 const citationElements = document.querySelectorAll('.citation-count');
 if (citationElements.length === 0) return;

 const queryItems = new Set();
 citationElements.forEach(el => {
 const arxivId = el.getAttribute('data-arxiv-id');
 const s2Id = el.getAttribute('data-s2-id');
 if (arxivId) queryItems.add({ id: arxivId, type: 'arxiv' });
 else if (s2Id) queryItems.add({ id: s2Id, type: 's2' });
 });

 const results = [];
 for (const item of queryItems) {
 const citations = await fetchCitations(item.id, item.type === 'arxiv');
 results.push({ id: item.id, citations });
 await new Promise(resolve => setTimeout(resolve, 300)); // 防止 S2 API 限流 (S2 免费版 1请求/秒)
 }

 citationElements.forEach(el => {
 const arxivId = el.getAttribute('data-arxiv-id');
 const s2Id = el.getAttribute('data-s2-id');
 const targetId = arxivId || s2Id;

 const result = results.find(r => r.id === targetId);
 if (result && result.citations !== null && result.citations > 0) { // 引用量为0时可以不显示
 el.textContent = ` ${formatNumber(result.citations)}`;
 el.style.display = 'inline';
 }
 });
 }

 // --------------------------------------------------------
 // 4. 统一下发执行
 // --------------------------------------------------------
 function initStatsTracking() {
 updateAllStars();
 updateAllCitations();
 }

 if (document.readyState === 'loading') {
 document.addEventListener('DOMContentLoaded', initStatsTracking);
 } else {
 setTimeout(initStatsTracking, 100);
 }
 </script>
 <script>
 document.addEventListener("DOMContentLoaded", function() {
 let isSnapping = false;
 let hasScrolledPastHero = false;

 window.addEventListener('scroll', () => {
 const scrollY = window.scrollY;
 const heroHeight = window.innerHeight;

 // 当处于首屏顶部，且向下滚动超过 30 像素时，触发平滑吸附
 if (scrollY > 30 && scrollY < heroHeight / 2 && !isSnapping && !hasScrolledPastHero) {
 isSnapping = true;
 hasScrolledPastHero = true;

 // 自动平滑滚动到 About 区域
 document.getElementById('about').scrollIntoView({ behavior: 'smooth' });

 // 动画大概需要 800ms，期间锁定状态防止抖动
 setTimeout(() => { isSnapping = false; }, 800);
 } 
 // 当用户滚回绝对顶部时，重置状态
 else if (scrollY === 0) {
 hasScrolledPastHero = false;
 isSnapping = false;
 }
 });
 });
 </script>

</body>
</html>","command":"","real_command":"curl -s https://gongyeliu.github.io/ 2>/dev/null | tail -n +500","status":"success","operation":""},"display_name":"执行命令","sub_content":"curl -s https://gongyeliu.github.io/ 2>/dev/null | tail -n +500","sub_content_tip":"curl -s https://gongyeliu.github.io/ 2>/dev/null | tail -n +500"},"messageId":"019ce0b46c877b2e8b0225046def72ab","toolCallId":"tooluse_dVM7U3fXHiqE7LjyoqkY3R","content":" // 1. 每次点击，先强制把所有文章隐去并下沉，制造“刷新”感
