{"type":"TOOL_CALL_RESULT","timestamp":1773296487,"rawEvent":{"message_id":"019ce0b46c877b2e8b0225046def72ab","conversation_id":"019ce0b2bc5575239725bf81fcda9410","tool_call_id":"tooluse_8rwI4xZ6hdaKCUSOXmI7tf","result":{"content":"/* 0. 字体引入 */
@font-face { font-family: 'Lato'; font-style: normal; font-weight: 400; src: local('Lato Regular'), url(https://fonts.gstatic.com/s/lato/v15/S6uyw4BMUTPHjxAwXiWtFCfQ7A.woff2) format('woff2'); }
@font-face { font-family: 'Lato'; font-style: normal; font-weight: 700; src: local('Lato Bold'), url(https://fonts.gstatic.com/s/lato/v15/S6u9w4BMUTPHh6UVSwaPGQ3q5d0N7w.woff2) format('woff2'); }
@font-face { font-family: 'Lato'; font-style: italic; font-weight: 400; src: local('Lato Italic'), url(https://fonts.gstatic.com/s/lato/v15/S6u8w4BMUTPHjxsAUi-qNiXg7eU0.woff2) format('woff2'); }
@font-face { font-family: 'Lato'; font-style: italic; font-weight: 700; src: local('Lato Bold Italic'), url(https://fonts.gstatic.com/s/lato/v15/S6u_w4BMUTPHjxsI5wq_FQftx9897sxZ.woff2) format('woff2'); }

/* 1. 颜色与变量定义 */
:root {
 --bg-color: rgb(34, 39, 44);
 --text-primary: #f0f0f0;
 --text-secondary: #8b949e; 
 --heading-color: rgb(23, 165, 236);
 --pub-title-color: rgb(185, 232, 255);
 --name-color: #f0f0f0;
 --pub-link-color: #3098ff;
 --link-color: #3098ff;
 --link-hover: #ffac4d;
 --highlight-name: #ffac4d;
 --highlight-pub: #ffac4d; 
 --venue-tag-bg: #b9162e; 
 --font-main: 'Aptos', 'Lato', Verdana, Helvetica, sans-serif;
 --font-serif: 'Noto Serif', 'Lato', Verdana, Helvetica, sans-serif;
}

/* 2. 全局重置与基础设置 */
* { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; }

body {
 background-color: var(--bg-color);
 color: var(--text-primary);
 font-family: var(--font-main);
 font-size: 16px; 
 line-height: 1.5;
}

.container {
 width: 90%;
 max-width: 1080px;
 margin: 0 auto;
 padding: 40px 0;
}

a {
 color: inherit; 
 text-decoration: none;
 position: relative; 
 padding-bottom: 2px; 
 transition: color 0.3s ease;
}

a::before {
 content: '';
 position: absolute;
 bottom: 0;
 left: 0;
 width: 100%;
 height: 1px;
 background: rgba(139, 148, 158, 0.4);
 z-index: 1;
}

a::after {
 content: '';
 position: absolute;
 bottom: 0;
 left: 0;
 width: 0;
 height: 1.5px;
 background: var(--link-hover);
 transition: width 0.3s ease;
 z-index: 2;
}

a:hover { color: var(--link-hover); }
a:hover::after { width: 100%; }
a:has(img)::before, a:has(img)::after { display: none; }
a.color-a { color: var(--pub-link-color); }
img, video { border-radius: 15px; }

/* 3. Section 与高级下划线 */
section {
 scroll-margin-top: 80px;
 margin-bottom: 50px;
}

.intro-section {
 display: flex;
 align-items: center;
 gap: 40px;
 margin-bottom: 50px;
 line-height: 1.8;
}

.profile-img {
 height: 180px;
 max-width: 100%;
}

.name {
 font-family: var(--font-main);
 font-size: 32px;
 color: var(--name-color);
 margin-bottom: 10px;
}


.section-title {
 font-family: var(--font-serif);
 font-size: 26px;
 color: var(--heading-color);
 position: relative; 
 padding-bottom: 12px; 
 margin-bottom: 30px; 
}

.section-title::after {
 content: '';
 position: absolute;
 left: 0;
 bottom: 0;
 width: 50px; 
 height: 3px; 
 background: var(--heading-color); 
 border-radius: 2px;
}

.section-subtitle {
 font-size: 14px;
 color: var(--text-primary);
 margin-top: -15px;
 margin-bottom: 25px;
}

.content-block p { margin-bottom: 15px; }

/* 4. 列表项 (Education / Internship) */
.list-item { display: flex; align-items: center; gap: 20px; margin-bottom: 25px; }
.list-item .logo { height: 70px; border-radius: 8px; }
.list-content { flex: 1; }
.item-title { font-family: var(--font-serif); font-size: 16px; font-weight: 600; color: var(--pub-title-color); }
.list-date { font-weight: bold; font-size: 15px; }

/* 5. Publications 核心 */
.pub-item { display: flex; gap: 30px; margin-bottom: 10px; padding: 15px; border-radius: 12px; transition: background-color 0.2s; }
.pub-item:hover { background-color: #151515; }

.pub-img {
 flex: 0 0 25%;
 aspect-ratio: 16 / 9;
 background: transparent;
 border-radius: 12px;
 display: flex;
 align-items: center;
 justify-content: center; 
 overflow: hidden;
}

.img-wrapper { position: relative; display: flex; max-width: 100%; max-height: 100%; }
.img-wrapper img { display: block; max-width: 100%; max-height: 100%; border-radius: 6px; }

.img-static { position: relative; z-index: 1; transition: opacity 0.3s ease; }
.img-hover { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 2; opacity: 0; object-fit: contain; transition: opacity 0.3s ease; }
.pub-item:hover .img-static { opacity: 0; }
.pub-item:hover .img-hover { opacity: 1; }

.venue-tag {
 position: absolute; top: 6px; left: 6px; z-index: 10; display: inline-block; font-size: 11px;
 font-weight: normal; color: #fff; background-color: var(--venue-tag-bg);
 padding: 1px 5px 2px 5px; border-radius: 4px; box-shadow: 2px 2px 1px rgba(0, 0, 0, 0.4); pointer-events: none;
}

.pub-info { flex: 1; }
.pub-title { font-family: var(--font-serif); font-size: 17px; font-weight: 700; color: var(--pub-title-color); margin: 4px 0; display: block; }
.pub-authors { font-size: 15px; color: var(--text-secondary); margin-bottom: 8px; }
.highlight-me { color: var(--highlight-name); text-decoration: underline; text-underline-offset: 3px; }
.highlight-pub { color: var(--highlight-pub); font-weight: normal; }
.pub-venue { font-size: 15px; margin-top: 12px; margin-bottom: 1px; }

.pub-desc {
 font-size: 14px; font-style: italic; color: var(--text-secondary);
 margin-top: 16px; padding-left: 10px; border-left: 2px solid rgba(255, 255, 255, 0.15); line-height: 1.2;
}
.pub-item:hover .pub-desc { border-left-color: rgba(255, 172, 77, 0.5); }

.pub-links { display: flex; gap: 10px; margin-top: 0px; margin-bottom: 8px; }
.pub-links a { color: var(--pub-link-color); text-decoration: none; }
.pub-stat { font-size: 13px; color: var(--text-secondary); margin-left: 4px; font-family: var(--font-main); transition: color 0.3s ease; font-weight: normal; }
.pub-links a:hover .pub-stat { color: inherit; }

/* 6. 过滤气泡 */
.filter-controls { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 30px; }
.filter-btn {
 background: rgba(255, 255, 255, 0.05); color: var(--text-secondary); border: 1px solid rgba(255, 255, 255, 0.1);
 padding: 6px 16px; border-radius: 20px; font-size: 14px; cursor: pointer; transition: all 0.3s ease; font-family: var(--font-main);
}
.filter-btn:hover { background: rgba(255, 255, 255, 0.1); color: var(--text-primary); }
.filter-btn.active { background: var(--link-hover); color: #000; border-color: var(--link-hover); font-weight: bold; }
.pub-item { transition: opacity 0.4s ease, transform 0.4s ease; }
.pub-item.hidden { display: none; }

/* 7. Footer */
footer { text-align: right; font-size: 14px; padding-top: 20px; margin-top: 40px; }


/* =========================================
 8. 全屏首屏 (Hero Screen)
========================================= */
.hero-screen {
 height: 100vh; 
 width: 100%;
 display: flex;
 align-items: center;
 justify-content: center;
 position: relative;
 background: radial-gradient(circle at center, rgba(45, 52, 58, 1) 0%, var(--bg-color) 100%); 
}

.hero-content {
 text-align: center;
 animation: fadeInUp 1s ease-out forwards; 
}

.hero-avatar {
 width: 130px; height: 130px; border-radius: 50%; object-fit: cover;
 border: 2px solid rgba(255, 255, 255, 0.1); margin-bottom: 20px; box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
}

.hero-name { font-family: var(--font-serif); font-size: 36px; color: var(--name-color); margin-bottom: 8px; letter-spacing: 1px; }
.hero-title { font-size: 16px; color: var(--text-secondary); margin-bottom: 30px; }
.hero-subtitle, .hero-contact { font-size: 15px; color: var(--text-secondary); margin-bottom: 6px; }
.hero-contact { margin-bottom: 30px; }

.hero-nav { display: flex; flex-direction: column; gap: 12px; margin-bottom: 40px; }
.hero-nav a { font-family: var(--font-serif); font-size: 17px; color: var(--text-primary); text-decoration: none; font-weight: bold; transition: color 0.3s ease; }
.hero-nav a::before, .hero-nav a::after { display: none; }
.hero-nav a:hover { color: var(--link-hover); }

.hero-socials { display: flex; justify-content: center; gap: 20px; }
.hero-socials a { font-size: 14px; color: var(--text-secondary); text-decoration: none; }
.hero-socials a::before, .hero-socials a::after { display: none; }
.hero-socials a:hover { color: var(--link-hover); }

/* 下滑提示动效 */
.scroll-indicator { position: absolute; bottom: 40px; color: var(--text-secondary); animation: bounce 2s infinite; opacity: 0.7; }
.scroll-indicator:hover { color: var(--link-hover); opacity: 1; }
.scroll-indicator::before, .scroll-indicator::after { display: none; }

@keyframes bounce {
 0%, 20%, 50%, 80%, 100% { transform: translateY(0); }
 40% { transform: translateY(-15px); }
 60% { transform: translateY(-7px); }
}

@keyframes fadeInUp {
 from { opacity: 0; transform: translateY(20px); }
 to { opacity: 1; transform: translateY(0); }
}

/* =========================================
 9. 吸顶导航栏 (Sticky Nav)
========================================= */
.sticky-nav {
 position: sticky; top: 0; z-index: 1000;
 background: rgba(34, 39, 44, 0.85); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
 border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.nav-container { width: 90%; max-width: 1080px; margin: 0 auto; display: flex; justify-content: space-between; align-items: center; height: 60px; }

.nav-brand {
 font-family: var(--font-serif); font-weight: 700; font-size: 15px; color: var(--name-color);
 letter-spacing: 1px; text-decoration: none; transition: color 0.3s ease;
}
.nav-brand:hover { color: var(--link-hover); }
.nav-brand::before, .nav-brand::after { display: none !important; }

.nav-links { display: flex; gap: 24px; }
.nav-links a { font-family: var(--font-main); font-size: 14px; color: var(--text-secondary); text-decoration: none; transition: color 0.3s ease; }
.nav-links a::before, .nav-links a::after { display: none; }
