.nav-links a:hover { color: var(--link-hover); }


/* 2. 新增通用的吸顶表头容器 (核心) */
.sticky-header {
 position: sticky;
 top: 61px; /* 刚好卡在顶部导航栏(60px + 1px边框)的下方 */
 z-index: 900; /* 保证在正文上方，且在顶部导航(1000)的下方 */
 background-color: var(--bg-color); /* 必须使用背景色，防止下方滚动内容透字 */
 padding-top: 15px; /* 顶部呼吸空间 */
