    /* ============ 7. Footer ============ */
    footer { text-align: right; font-size: 14px; padding-top: 20px; margin-top: 40px; }

    /* ============ 8. 全屏首屏 Hero ============ */
    .hero-screen {
      height: 100vh;
      width: 100%;
      display: flex;
      align-items: center;
      justify-content: center;
