    .hero-name { font-family: var(--font-serif); font-size: 36px; color: var(--name-color); margin-bottom: 8px; letter-spacing: 1px; }
    .hero-title { font-size: 16px; color: var(--text-secondary); margin-bottom: 30px; }
    .hero-subtitle, .hero-contact { font-size: 15px; color: var(--text-secondary); margin-bottom: 6px; }
    .hero-contact { margin-bottom: 30px; }

    .hero-nav { display: flex; flex-direction: column; gap: 12px; margin-bottom: 40px; }
    .hero-nav a { font-family: var(--font-serif); font-size: 17px; color: var(--text-primary); text-decoration: none; font-weight: bold; transition: color 0.3s ease; }
    .hero-nav a::before, .hero-nav a::after { display: none; }
    .hero-nav a:hover { color: var(--link-hover); }

    .hero-socials { display: flex; justify-content: center; gap: 20px; }
    .hero-socials a { font-size: 14px; color: var(--text-secondary); text-decoration: none; }
    .hero-socials a::before, .hero-socials a::after { display: none; }
    .hero-socials a:hover { color: var(--link-hover); }

    /* 下滑提示动效 */
    .scroll-indicator { position: absolute; bottom: 40px; color: var(--text-secondary); animation: bounce 2s infinite; opacity: 0.7; }
    .scroll-indicator:hover { color: var(--link-hover); opacity: 1; }
    .scroll-indicator::before, .scroll-indicator::after { display: none; }

    @keyframes bounce {
      0%, 20%, 50%, 80%, 100% { transform: translateY(0); }
      40% { transform: translateY(-15px); }
      60% { transform: translateY(-7px); }
    }

    @keyframes fadeInUp {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    /* ============ 9. 吸顶导航栏 ============ */
    .sticky-nav {
      position: sticky; top: 0; z-index: 1000;
      background: rgba(34, 39, 44, 0.85); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
      border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    }

    .nav-container { width: 90%; max-width: 1080px; margin: 0 auto; display: flex; justify-content: space-between; align-items: center; height: 60px; }

    .nav-brand {
      font-family: var(--font-serif); font-weight: 700; font-size: 15px; color: var(--name-color);
      letter-spacing: 1px; text-decoration: none; transition: color 0.3s ease;
    }
    .nav-brand:hover { color: var(--link-hover); }
    .nav-brand::before, .nav-brand::after { display: none !important; }

    .nav-links { display: flex; gap: 24px; }
    .nav-links a { font-family: var(--font-main); font-size: 14px; color: var(--text-secondary); text-decoration: none; transition: color 0.3s ease; }
    .nav-links a::before, .nav-links a::after { display: none; }
    .nav-links a:hover { color: var(--link-hover); }

    .sticky-filters {
      position: sticky;
      top: 61px;
      z-index: 900;
      background-color: var(--bg-color);
      padding-top: 15px;
      padding-bottom: 10px;
      margin-bottom: 20px;
      scroll-margin-top: 61px;
    }

    /* ============ 10. 响应式适配 ============ */
    @media (max-width: 768px) {
      .intro-section { flex-direction: column; text-align: center; gap: 20px; }
      .profile-img { height: 140px; }
      .name { font-size: 26px; }
      .pub-item { flex-direction: column; }
      .pub-img { flex: none; width: 100%; }
      .list-item { flex-direction: column; text-align: center; }
      .list-date { margin-top: 5px; }
      .hero-name { font-size: 28px; }
      .nav-links { gap: 14px; }
      .nav-links a { font-size: 12px; }
      .nav-brand { font-size: 13px; }
    }

    .pub-links a { color: var(--pub-link-color); }
  </style>
</head>

