  <!-- ======== 主要内容区 ======== -->
  <div class="container">

    <!-- About Section -->
    <section id="about">
      <header class="intro-section">
        <img src="bio.jpg" alt="Jiexuan Zhang" class="profile-img">
        <div class="intro-text">
          <h1 class="name">Jiexuan Zhang (张杰轩)</h1>
          <p>Master Student <a href="https://www.pku.edu.cn/">@Peking University</a>, Beijing</p>
          <p>Contact: jiexuan@stu.pku.edu.cn</p>
          <p class="pub-links">
            <a href="mailto:jiexuan@stu.pku.edu.cn">E-mail</a> /
            <a href="https://scholar.google.com/citations?user=HvwAsDgAAAAJ&hl=zh-CN">Scholar</a> /
            <a href="https://github.com/Jiexuanz">GitHub</a>
          </p>
        </div>
      </header>

      <h2 class="section-title">About Me</h2>
      <div class="content-block">
        <p>Hi, I'm Jiexuan Zhang, a Master student at <a href="https://www.pku.edu.cn/">Peking University</a>, advised by <a href="https://jianzhang.tech/" class="color-a">Prof. Jian Zhang</a>.</p>
        <p>Prior to that, I received my B.Eng degree (2020-2024) from <a href="https://www.buaa.edu.cn/">Beihang University</a>, Shenyuan Honor College, majoring in Software Engineering.</p>
        <p>My research interests include <em>Image / Video Generation</em> and <em>Diffusion Models</em>, with a focus on post-training techniques and controllable generation.</p>
      </div>
    </section>

    <!-- Education Section -->
    <section id="education">
      <h2 class="section-title">Education</h2>

      <div class="list-item">
        <img src="educations/pku.png" alt="PKU Logo" class="logo">
        <div class="list-content">
          <span class="item-title">Peking University</span><br>
          Master Student in Computer Science<br>
          Advisor: <a href="https://jianzhang.tech/" class="color-a">Prof. Jian Zhang</a>
        </div>
        <div class="list-date">Sep. 2024 - Present</div>
      </div>

      <div class="list-item">
        <img src="educations/BUAA.png" alt="BUAA Logo" class="logo">
        <div class="list-content">
          <span class="item-title">Beihang University</span><br>
          Bachelor Student in Software Engineering, Shenyuan Honor College
        </div>
        <div class="list-date">Sep. 2020 - Jul. 2024</div>
      </div>
    </section>

    <!-- Publications Section -->
    <section id="publications">
      <h2 class="section-title">Publications</h2>

      <div class="filter-controls sticky-filters" id="pub-filters">
        <div class="filter-controls">
          <button class="filter-btn active" data-filter="all">All</button>
          <button class="filter-btn" data-filter="generation">Generation</button>
          <button class="filter-btn" data-filter="diffusion">Diffusion</button>
        </div>
      </div>

      <!-- AlignedGen -->
      <article class="pub-item" data-tags="generation, diffusion">
