    .nav-links { display: flex; gap: 24px; align-items: center; }
    .nav-links a { font-family: var(--font-main); font-size: 15px; color: var(--text-secondary); text-decoration: none; transition: color 0.3s ease; }
    .nav-links a::before, .nav-links a::after { display: none; }
