  <script>
    // 论文过滤功能
    document.addEventListener("DOMContentLoaded", function() {
      const filterBtns = document.querySelectorAll('.filter-btn');
      const pubItems = document.querySelectorAll('.pub-item');

      filterPublications('all');

      filterBtns.forEach(btn => {
        btn.addEventListener('click', function() {
          filterBtns.forEach(b => b.classList.remove('active'));
          this.classList.add('active');

          const filterBar = document.getElementById('pub-filters');
          filterBar.style.position = 'static';
          const targetY = filterBar.getBoundingClientRect().top + window.scrollY - 61 - 10;
          filterBar.style.position = '';
          window.scrollTo({ top: targetY, behavior: 'smooth' });

          const filterValue = this.getAttribute('data-filter');
          filterPublications(filterValue);
        });
      });

      function filterPublications(filterValue) {
        pubItems.forEach(item => {
          item.style.opacity = '0';
          item.style.transform = 'translateY(10px)';
        });

        setTimeout(() => {
          let delay = 0;
          pubItems.forEach(item => {
            const itemTags = item.getAttribute('data-tags');
            if (filterValue === 'all' || (itemTags && itemTags.includes(filterValue))) {
              item.classList.remove('hidden');
              setTimeout(() => {
                item.style.opacity = '1';
                item.style.transform = 'translateY(0)';
              }, delay);
              delay += 50;
            } else {
              item.classList.add('hidden');
            }
          });
        }, 150);
      }
    });
  </script>

  <script>
    // GitHub Stars & 引用量抓取
    function formatNumber(count) {
      if (count >= 1000) return (count / 1000).toFixed(1) + 'k';
      return count.toString();
    }

    async function fetchGitHubStars(repo) {
      try {
        const response = await fetch(`https://api.github.com/repos/${repo}`, {
          headers: { 'Accept': 'application/vnd.github.v3+json' }
        });
        if (response.ok) {
          const data = await response.json();
          return data.stargazers_count;
        }
      } catch (error) { console.error(`Error fetching stars for ${repo}:`, error); }
      return null;
    }

    async function updateAllStars() {
      const starElements = document.querySelectorAll('.github-stars[data-github-repo]');
      if (starElements.length === 0) return;
      const repos = new Set();
      starElements.forEach(el => repos.add(el.getAttribute('data-github-repo')));
      const results = [];
      for (const repo of repos) {
        const stars = await fetchGitHubStars(repo);
        results.push({ repo, stars });
        await new Promise(resolve => setTimeout(resolve, 200));
      }
      starElements.forEach(el => {
        const repo = el.getAttribute('data-github-repo');
        const result = results.find(r => r.repo === repo);
        if (result && result.stars !== null) {
          el.textContent = `⭐ ${formatNumber(result.stars)}`;
          el.style.display = 'inline';
        }
      });
    }

    async function fetchCitations(identifier) {
      try {
        const response = await fetch(`https://api.semanticscholar.org/graph/v1/paper/ARXIV:${identifier}?fields=citationCount`);
        if (response.ok) {
          const data = await response.json();
          return data.citationCount;
        }
      } catch (error) { console.error(`Error fetching citations for ${identifier}:`, error); }
      return null;
    }

    async function updateAllCitations() {
      const citationElements = document.querySelectorAll('.citation-count');
      if (citationElements.length === 0) return;
      const queryItems = new Set();
      citationElements.forEach(el => {
        const arxivId = el.getAttribute('data-arxiv-id');
        if (arxivId) queryItems.add(arxivId);
      });
      const results = [];
      for (const id of queryItems) {
        const citations = await fetchCitations(id);
        results.push({ id, citations });
        await new Promise(resolve => setTimeout(resolve, 300));
      }
      citationElements.forEach(el => {
        const arxivId = el.getAttribute('data-arxiv-id');
        const result = results.find(r => r.id === arxivId);
        if (result && result.citations !== null && result.citations > 0) {
          el.textContent = ` ${formatNumber(result.citations)}`;
          el.style.display = 'inline';
        }
      });
    }

    function initStatsTracking() {
      updateAllStars();
      updateAllCitations();
    }

    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', initStatsTracking);
    } else {
      setTimeout(initStatsTracking, 100);
    }
  </script>

  <script>
    // 主题切换功能
    (function() {
      const toggle = document.getElementById('themeToggle');
      const savedTheme = localStorage.getItem('theme') || 'dark';
      if (savedTheme === 'light') {
        document.documentElement.setAttribute('data-theme', 'light');
      }
      toggle.addEventListener('click', () => {
        const current = document.documentElement.getAttribute('data-theme');
        const next = current === 'light' ? 'dark' : 'light';
        if (next === 'light') {
          document.documentElement.setAttribute('data-theme', 'light');
        } else {
          document.documentElement.removeAttribute('data-theme');
        }
        localStorage.setItem('theme', next);
      });
    })();
  </script>

  <script>
    // 首屏吸附滚动效果
    document.addEventListener("DOMContentLoaded", function() {
      let isSnapping = false;
      let hasScrolledPastHero = false;

      window.addEventListener('scroll', () => {
        const scrollY = window.scrollY;
        const heroHeight = window.innerHeight;

        if (scrollY > 30 && scrollY < heroHeight / 2 && !isSnapping && !hasScrolledPastHero) {
          isSnapping = true;
          hasScrolledPastHero = true;
          document.getElementById('about').scrollIntoView({ behavior: 'smooth' });
          setTimeout(() => { isSnapping = false; }, 800);
        } else if (scrollY === 0) {
          hasScrolledPastHero = false;
          isSnapping = false;
        }
      });
    });
  </script>
