 // 首屏吸附滚动效果（改进版 v2）
 document.addEventListener("DOMContentLoaded", function() {
 let hasSnapped = false;
 let isSnapping = false;
 const aboutEl = document.getElementById('about');

 function doSnap() {
 if (hasSnapped || isSnapping) return;
 hasSnapped = true;
 isSnapping = true;

 // 禁用页面滚动，防止动画期间用户滚动导致冲突
 document.body.style.overflow = 'hidden';
 document.documentElement.style.overflow = 'hidden';

 const targetY = aboutEl.getBoundingClientRect().top + window.scrollY;
 window.scrollTo({ top: targetY, behavior: 'smooth' });

 // 检测滚动动画完成
 let checkCount = 0;
 let lastScrollY = window.scrollY;
 const checkDone = setInterval(() => {
 checkCount++;
 if (Math.abs(window.scrollY - lastScrollY) < 1 || checkCount > 60) {
 // 滚动停止或超过 1.2 秒，解除锁定
 clearInterval(checkDone);
 document.body.style.overflow = '';
 document.documentElement.style.overflow = '';
 isSnapping = false;
 }
 lastScrollY = window.scrollY;
 }, 20);
 }

 // 使用 wheel 事件检测用户主动向下滚动意图
 window.addEventListener('wheel', function(e) {
 if (isSnapping) {
 e.preventDefault();
 return;
 }
 if (e.deltaY > 0 && !hasSnapped && window.scrollY < window.innerHeight * 0.3) {
 e.preventDefault();
 doSnap();
 }
 }, { passive: false });

 // 触屏设备处理
 let touchStartY = 0;
 window.addEventListener('touchstart', function(e) {
 touchStartY = e.touches[0].clientY;
 }, { passive: true });

 window.addEventListener('touchmove', function(e) {
 if (isSnapping) {
 e.preventDefault();
 }
 }, { passive: false });

 window.addEventListener('touchend', function(e) {
 const touchEndY = e.changedTouches[0].clientY;
 const deltaY = touchStartY - touchEndY;
 if (deltaY > 30 && !hasSnapped && !isSnapping && window.scrollY < window.innerHeight * 0.3) {
 doSnap();
 }
 }, { passive: true });

 // 当用户回到首屏顶部时，重置状态，允许再次吸附
 let resetTimer = null;
 window.addEventListener('scroll', function() {
 if (isSnapping) return;
 if (window.scrollY === 0) {
 // 延迟重置，避免回弹时立即触发
 clearTimeout(resetTimer);
 resetTimer = setTimeout(() => {
 if (window.scrollY === 0) {
 hasSnapped = false;
 }
 }, 300);
 }
 }, { passive: true });
 });
 </script>","apply_mode":"apply_only"}},"timestamp":1773299484,"type":"TOOL_CALL_ARGS"}

