 clearInterval(checkDone);
 document.body.style.overflow = '';
 document.documentElement.style.overflow = '';
 isSnapping = false;

 // 进入冷却期：继续拦截 wheel 事件一段时间，消化触控板惯性
 isCoolingDown = true;
