 // 使用 wheel 事件检测用户主动向下滚动意图
 window.addEventListener('wheel', function(e) {
 // 吸附动画中：完全阻止
 if (isSnapping) {
 e.preventDefault();
 return;
 }
 // 冷却期中：阻止向下的大幅滚动（消化惯性），允许小幅和向上滚动
 if (isCoolingDown && e.deltaY > 5) {
 e.preventDefault();
 return;
 }
 // 首屏向下滚动：触发吸附
 if (e.deltaY > 0 && !hasSnapped && window.scrollY < window.innerHeight * 0.3) {
 e.preventDefault();
 doSnap();
 }
 }, { passive: false });

 // 触屏设备处理
 let touchStartY = 0;
 window.addEventListener('touchstart', function(e) {
 touchStartY = e.touches[0].clientY;
 }, { passive: true });

 window.addEventListener('touchmove', function(e) {
 if (isSnapping) {
 e.preventDefault();
 }
 }, { passive: false });

 window.addEventListener('touchend', function(e) {
 const touchEndY = e.changedTouches[0].clientY;
 const deltaY = touchStartY - touchEndY;
 if (deltaY > 30 && !hasSnapped && !isSnapping && window.scrollY < window.innerHeight * 0.3) {
 doSnap();
 }
 }, { passive: true });

 // 当用户回到首屏顶部时，重置状态，允许再次吸附
 let resetTimer = null;
 window.addEventListener('scroll', function() {
 if (isSnapping) return;
 if (window.scrollY === 0) {
 clearTimeout(resetTimer);
 resetTimer = setTimeout(() => {
 if (window.scrollY === 0) {
 hasSnapped = false;
 }
 }, 300);
 }
 }, { passive: true });
 });
